            }
            object baseId = this.safeStringLower(candidate, "baseId", "");
            object quoteId = this.safeStringLower(candidate, "quoteId", "");
            if (isTrue(isEqual(add(((string)baseId), ((string)quoteId)), wsBaseQuote)))
            {
                return candidate;
            }
        }
